const question = $.input.question;
const schema = $.input.schemaDescription;
const dbType = $.input.databaseType || 'PostgreSQL';
const context = $.input.additionalContext || '';

let prompt = 'You are an expert SQL developer. Generate a SQL query from the natural language question using the provided schema.\n\n';
prompt += 'DATABASE TYPE: ' + dbType + '\n\n';
prompt += 'SCHEMA:\n' + schema + '\n\n';
if (context) prompt += 'ADDITIONAL CONTEXT: ' + context + '\n\n';
prompt += 'QUESTION: ' + question + '\n\n';
prompt += 'INSTRUCTIONS:\n';
prompt += '- Generate a correct, optimized SQL query for ' + dbType + '\n';
prompt += '- Use proper JOINs, WHERE clauses, GROUP BY as needed\n';
prompt += '- Add table aliases for readability\n';
prompt += '- Include ORDER BY when it makes sense\n';
prompt += '- Explain each part of the query\n';
prompt += '- Suggest potential indexes for optimization\n';
prompt += '- If the question is ambiguous, state your assumptions\n\n';
prompt += 'Return ONLY valid JSON:\n';
prompt += '{\n';
prompt += '  "sqlQuery": "SELECT ... FROM ... WHERE ...",\n';
prompt += '  "explanation": "Step-by-step explanation of the query logic",\n';
prompt += '  "assumptions": ["assumption 1"],\n';
prompt += '  "suggestedIndexes": ["CREATE INDEX idx_name ON table(column)"],\n';
prompt += '  "complexity": "simple|moderate|complex",\n';
prompt += '  "expectedResultDescription": "what the query will return",\n';
prompt += '  "alternativeApproach": "an alternative way to write this query if applicable"\n';
prompt += '}';

return { prompt };

let raw = $.steps.aiGenerate.output || '';
raw = raw.replace(/^```json\s*/i, '').replace(/^```\s*/i, '').replace(/\s*```$/i, '').trim();
try { return JSON.parse(raw); } catch(e) { return { sqlQuery: raw, explanation: 'Could not parse structured response', assumptions: [], suggestedIndexes: [], complexity: 'unknown', expectedResultDescription: '', alternativeApproach: '' }; }

const ai = $.steps.parseAI.output;
const question = $.input.question;
const dbType = $.input.databaseType || 'PostgreSQL';

const complexityEmoji = ai.complexity === 'simple' ? ':large_green_circle:' : ai.complexity === 'complex' ? ':red_circle:' : ':large_yellow_circle:';

const blocks = [];
blocks.push({ type: 'header', text: { type: 'plain_text', text: 'AI SQL Query Generator' } });
blocks.push({ type: 'section', text: { type: 'mrkdwn', text: '*Question:* ' + question } });
blocks.push({ type: 'section', text: { type: 'mrkdwn', text: '*Database:* ' + dbType + ' | ' + complexityEmoji + ' Complexity: *' + (ai.complexity || 'unknown') + '*' } });
blocks.push({ type: 'divider' });

const sqlText = '```' + (ai.sqlQuery || 'No query generated') + '```';
blocks.push({ type: 'section', text: { type: 'mrkdwn', text: '*Generated SQL:*\n' + sqlText.slice(0, 1800) } });
blocks.push({ type: 'divider' });

const explanation = (ai.explanation || '').slice(0, 1800);
blocks.push({ type: 'section', text: { type: 'mrkdwn', text: '*Explanation:*\n' + explanation } });

if (ai.expectedResultDescription) {
  blocks.push({ type: 'section', text: { type: 'mrkdwn', text: '*Expected Result:* ' + ai.expectedResultDescription } });
}

if (ai.assumptions && ai.assumptions.length > 0) {
  blocks.push({ type: 'section', text: { type: 'mrkdwn', text: '*Assumptions:*\n' + ai.assumptions.map((a, i) => (i + 1) + '. ' + a).join('\n') } });
}

if (ai.suggestedIndexes && ai.suggestedIndexes.length > 0) {
  blocks.push({ type: 'section', text: { type: 'mrkdwn', text: '*Suggested Indexes:*\n```' + ai.suggestedIndexes.join('\n') + '```' } });
}

if (ai.alternativeApproach) {
  blocks.push({ type: 'section', text: { type: 'mrkdwn', text: '*Alternative Approach:*\n' + ai.alternativeApproach.slice(0, 800) } });
}

blocks.push({ type: 'context', elements: [{ type: 'mrkdwn', text: 'Powered by Claude AI | ' + dbType }] });

const fallback = 'SQL query generated for: ' + question;
return { blocks, fallback };
